Here is a C++ function that converts markdown formatted text to html formatted text:

```cpp
#include <string>
#include <sstream>
#include <algorithm>

std::string markdownToHtml(const std::string& markdown) {
    std::string htmlResult;
    std::string currentLine;
    int lineNo = 0;
    bool inBlockquote = false;
    bool inBold = false;
    bool inItalic = false;
    bool inCode = false;
    bool inHeading = false;
    bool inList = false;

    for (auto ch : markdown) {
        if (ch == '\n') {
            ++lineNo;
            htmlResult += currentLine + "</span>";
            if (inBlockquote) {
                htmlResult += "<span style='font-size: smaller; font-style: italic;'>" + std::to_string(lineNo) + "</span>";
            } else if (inHeading) {
                htmlResult += "<span style='font-size: smaller; font-weight: normal;'>" + std::to_string(lineNo) + "</span>";
            } else if (inList) {
                htmlResult += "<span style='font-size: smaller; font-style: italic;'>" + std::to_string(lineNo) + "</span>";
            }
            currentLine.clear();
        } else if (ch == '#') {
            inHeading = true;
            inBold = false;
            inItalic = false;
            inCode = false;
            currentLine += "<span style='font-size: smaller; font-weight: bold;'>" + std::to_string(lineNo) + "</span>";
        } else if (ch == '-') {
            inList = true;
            inBold = false;
            inItalic = false;
            inCode = false;
            currentLine += "<span style='font-size: smaller; font-style: italic;'>" + std::to_string(lineNo) + "</span>";
        } else if (ch == '>') {
            inBlockquote = true;
            inBold = false;
            inItalic = false;
            inCode = false;
            currentLine += "<span style='font-size: smaller; font-style: italic;'>" + std::to_string(lineNo) + "</span>";
        } else if (ch == '**') {
            if (inBold) {
                inBold = false;
                currentLine += "</span>";
            } else {
                inBold = true;
                currentLine += "<span style='font-size: smaller; font-weight: bold;'>";
            }
        } else if (ch == '*') {
            if (inItalic) {
                inItalic = false;
                currentLine += "</span>";
            } else {
                inItalic = true;
                currentLine += "<span style='font-size: smaller; font-style: italic;'>";
            }
        } else if (ch == '`') {
            if (inCode) {
                inCode = false;
                currentLine += "</span>";
            } else {
                inCode = true;
                currentLine += "<span style='font-size: smaller; font-family: monospace;'>";
            }
        } else {
            currentLine += ch;
        }
    }

    htmlResult += currentLine;
    inBold = false;
    inItalic = false;
    inCode = false;
    inBlockquote = false;
    inList = false;
    inHeading = false;

    return htmlResult;
}
```

This function takes a std::string containing markdown formatted text and returns a std::string containing html formatted text.

